// Map go-wa webhook payload -> flat columns. Field names vary between go-wa
// versions; adjust the fallbacks if needed. Full payload kept in `raw`.
const p = $json.body ?? $json;

const chat_jid =
  p.chat_id || p.chatId ||
  (typeof p.from === 'string' && p.from.includes('@g.us') ? p.from : '') || '';
const sender_jid = p.sender_id || p.senderId || p.from || '';
const sender_name = p.pushname || p.push_name || p.sender_name || 'Unknown';

let media_type = null;
if (p.image) media_type = 'image';
else if (p.video) media_type = 'video';
else if (p.audio) media_type = 'audio';
else if (p.document) media_type = 'document';
else if (p.sticker) media_type = 'sticker';
else if (p.location) media_type = 'location';

const caption =
  (p.image && p.image.caption) || (p.video && p.video.caption) ||
  (p.document && p.document.caption) || '';
const text = (p.message && (p.message.text ?? p.message.conversation)) || p.text || caption || '';
const message = media_type && !text ? '[' + media_type + ']' : text;

const message_id = (p.message && p.message.id) || p.id || null;
const ts = p.timestamp ? new Date(p.timestamp).toISOString() : new Date().toISOString();

return [{ json: {
  message_id: message_id || null,
  chat_jid, sender_jid, sender_name, message, media_type,
  is_group: String(chat_jid).endsWith('@g.us'),
  timestamp: ts,
  raw: JSON.stringify(p),
} }];
